")\n  year           Int\n  month          Int? // 1-12, NULL = Jahresbudget\n  plannedAmount  Decimal  @map(\"planned_amount\") @db.Decimal(10, 2)\n  notes          String?  @db.Text\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n  updatedAt      DateTime @updatedAt @map(\"updated_at\")\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n\n  @@unique([organizationId, year, month])\n  @@map(\"budgets\")\n}\n\nmodel FinancialReport {\n  id             String   @id @default(uuid())\n  organizationId String?  @map(\"organization_id\") // NULL = übergreifend\n  reportType     String   @map(\"report_type\") // 'annual', 'quarterly', 'funding_request'\n  periodStart    DateTime @map(\"period_start\") @db.Date\n  periodEnd      DateTime @map(\"period_end\") @db.Date\n  totalDonations Decimal? @map(\"total_donations\") @db.Decimal(10, 2)\n  totalExpenses  Decimal? @map(\"total_expenses\") @db.Decimal(10, 2)\n  caseCount      Int?     @map(\"case_count\")\n  reportData     Json?    @map(\"report_data\") // Vollständiger Report als JSON\n  generatedAt    DateTime @default(now()) @map(\"generated_at\")\n  generatedBy    String   @map(\"generated_by\")\n\n  organization Organization? @relation(\"ReportGenerator\", fields: [organizationId], references: [id], onDelete: SetNull)\n  generator    User          @relation(\"ReportGenerator\", fields: [generatedBy], references: [id])\n\n  @@index([organizationId])\n  @@index([periodStart, periodEnd])\n  @@index([generatedAt(sort: Desc)])\n  @@map(\"financial_reports\")\n}\n\n// ============================================================\n// 6. SYSTEM\n// ============================================================\n\nmodel Activity {\n  id             String         @id @default(uuid())\n  organizationId String?        @map(\"organization_id\") // NULL = übergreifend\n  userId         String         @map(\"user_id\")\n  action         ActivityAction\n  targetType     String         @map(\"target_type\") // 'case', 'protocol', 'comment', etc.\n  targetId       String         @map(\"target_id\")\n  metadata       Json? // Extra info\n  createdAt      DateTime       @default(now()) @map(\"created_at\")\n\n  organization Organization? @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User          @relation(fields: [userId], references: [id])\n\n  @@index([organizationId])\n  @@index([userId])\n  @@index([targetType])\n  @@index([targetId])\n  @@index([createdAt(sort: Desc)])\n  @@index([organizationId, createdAt(sort: Desc)])\n  @@index([userId, createdAt(sort: Desc)])\n  @@index([targetType, targetId])\n  @@map(\"activities\")\n}\n\nmodel Notification {\n  id         String           @id @default(uuid())\n  userId     String           @map(\"user_id\")\n  type       NotificationType\n  title      String\n  message    String?          @db.Text\n  targetType String?          @map(\"target_type\") // 'case', 'protocol', 'comment'\n  targetId   String?          @map(\"target_id\")\n  read       Boolean          @default(false)\n  readAt     DateTime?        @map(\"read_at\")\n  createdAt  DateTime         @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([read])\n  @@index([createdAt(sort: Desc)])\n  @@index([userId, read, createdAt(sort: Desc)])\n  @@map(\"notifications\")\n}\n\nmodel Mention {\n  id               String @id @default(uuid())\n  mentionedUserId  String @map(\"mentioned_user_id\")\n  mentioningUserId String @map(\"mentioning_user_id\")\n\n  // Discriminator (für Queries / App-Logik)\n  targetType String @map(\"target_type\") // 'protocol' | 'case_comment' | 'protocol_comment'\n  targetId   String @map(\"target_id\") // = ID des Target-Objekts (frei, kein FK)\n\n  // Typisierte FKs für sauberen Cascade-Delete\n  protocolId        String? @map(\"protocol_id\")\n  caseCommentId     String? @map(\"case_comment_id\")\n  protocolCommentId String? @map(\"protocol_comment_id\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  mentionedUser   User             @relation(\"MentionedUser\", fields: [mentionedUserId], references: [id], onDelete: Cascade)\n  mentioningUser  User             @relation(\"MentioningUser\", fields: [mentioningUserId], references: [id])\n  protocol        Protocol?        @relation(fields: [protocolId], references: [id], onDelete: Cascade)\n  caseComment     CaseComment?     @relation(fields: [caseCommentId], references: [id], onDelete: Cascade)\n  protocolComment ProtocolComment? @relation(fields: [protocolCommentId], references: [id], onDelete: Cascade)\n\n  @@index([mentionedUserId])\n  @@index([mentionedUserId, createdAt(sort: Desc)])\n  @@index([targetType, targetId])\n  @@index([protocolId])\n  @@index([caseCommentId])\n  @@index([protocolCommentId])\n  @@map(\"mentions\")\n}\n\nmodel Todo {\n  id          String    @id @default(uuid())\n  userId      String    @map(\"user_id\")\n  title       String\n  description String?   @db.Text\n  done        Boolean   @default(false)\n  priority    Int       @default(2) // 1=Low, 2=Medium, 3=High\n  dueDate     DateTime? @map(\"due_date\") @db.Date\n  targetType  String?   @map(\"target_type\") // Optional: 'case', 'protocol'\n  targetId    String?   @map(\"target_id\")\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n  completedAt DateTime? @map(\"completed_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([done])\n  @@index([dueDate])\n  @@index([userId, done])\n  @@map(\"todos\")\n}\n\n// Event \nmodel Event {\n  id             String  @id @default(uuid())\n  organizationId String? @map(\"organization_id\")\n\n  title       String\n  description String? @db.Text\n  location    String?\n\n  startsAt DateTime @map(\"starts_at\")\n  endsAt   DateTime @map(\"ends_at\")\n  allDay   Boolean  @default(false) @map(\"all_day\")\n\n  color      EventColor      @default(SKY)\n  visibility EventVisibility @default(ORGANIZATION)\n\n  recurrence        EventRecurrence @default(NONE)\n  recurrenceEndDate DateTime?       @map(\"recurrence_end_date\") @db.Date\n\n  creatorId String @map(\"creator_id\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  organization Organization? @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  creator      User          @relation(\"EventCreator\", fields: [creatorId], references: [id])\n\n  @@index([organizationId, startsAt])\n  @@index([startsAt])\n  @@index([recurrence])\n  @@index([creatorId])\n  @@map(\"events\")\n}\n",
